final:
module RefModule(
    input [3:0] a,
    input [3:0] b,
    input carry_in,
    output [3:0] sum,
    output carry_out
);

    // Intermediate full adder sum and carry outputs
    wire [4:0] temp_sum;

    // Perform addition with carry-in
    wire __temp_sum_tmp = a + b + carry_in;
    assign temp_sum = __temp_sum_tmp;

    // Assign the sum and carry-out
    assign sum = temp_sum[3:0];
    assign carry_out = temp_sum[4];

endmodule
